import { Injectable, inject } from '@angular/core';
import { Observable, from, of } from 'rxjs';
import { SupabaseService } from '../../services/Base/supabase.service';
import { TimbratureSupabaseService } from './timbrature-supabase.service';
import { AuthService } from './timbrature-auth.adapter';
import { Company, User } from '../models';

export interface ManagerVisibilityConfig {
  mode?: 'self' | 'selected_users' | 'roles' | 'department';
  user_ids?: string[];
  roles?: string[];
  department_ids?: string[];
  can_view_all_employees?: boolean;
  can_manage_departments?: boolean;
  can_manage_job_titles?: boolean;
  can_view_reports?: boolean;
  can_edit_employees?: boolean;
  can_modify_timbrature?: boolean;
}

@Injectable({ providedIn: 'root' })
export class CompanyService {
  private plateaSupabase = inject(SupabaseService).getSupabaseClient();
  private timbratureSupabase = inject(TimbratureSupabaseService).getSupabaseClient();
  private authService = inject(AuthService);

  // Legge il ristorante da Platea e il record company da Timbrature
  // Li fonde in un unico oggetto Company
  getById(restaurantId: string): Observable<Company | null> {
    if (!restaurantId) return of(null);
    return from(this.fetchMerged(restaurantId));
  }

  getForUser(userId?: string | null, companyId?: string | null): Observable<Company | null> {
    const restaurantId = companyId || this.authService.companyId;
    if (!restaurantId) return of(null);
    return this.getById(restaurantId);
  }

  getByAdminUserId(userId: string): Observable<Company | null> {
    if (!userId) return of(null);
    return from(this.fetchMerged(null, userId));
  }

  private async fetchMerged(restaurantId: string | null, ownerId?: string): Promise<Company | null> {
    try {
      // 1. Leggi ristorante da Platea
      let restaurantQuery: any;
      if (restaurantId) {
        restaurantQuery = this.plateaSupabase
          .from('restaurants')
          .select('*')
          .eq('id', restaurantId)
          .maybeSingle();
      } else {
        restaurantQuery = this.plateaSupabase
          .from('restaurants')
          .select('*')
          .eq('owner_id', ownerId)
          .maybeSingle();
      }
      const { data: restaurant, error: restError } = await restaurantQuery;
      if (restError || !restaurant) return null;

      // 2. Leggi company da Timbrature (per i dati extra: opening_hours, punch_points, ecc.)
      const { data: company } = await this.timbratureSupabase
        .from('companies')
        .select('*')
        .eq('admin_user_id', restaurant.owner_id)
        .maybeSingle();

      // 3. Fondi i dati
      return {
        id: restaurant.id, // usiamo restaurant_id come id principale
        name: restaurant.name,
        admin_user_id: restaurant.owner_id,
        email: restaurant.email || company?.email || null,
        address: restaurant.address || company?.address || null,
        city: restaurant.city || company?.city || null,
        province: restaurant.province || company?.province || null,
        website: company?.website || null,
        vat: company?.vat || null,
        numero_telefono: company?.numero_telefono || restaurant.phone || null,
        opening_hours: company?.opening_hours || null,
        timbratura_type: company?.timbratura_type || 'libera',
        punch_points: company?.punch_points || [],
        closed_days: company?.closed_days || [],
        manager_visibility: company?.manager_visibility || {},
        // ID del record companies in Timbrature (per aggiornamenti)
        _timbrature_company_id: company?.id || null,
        created_at: restaurant.created_at,
        updated_at: restaurant.updated_at,
      } as any;
    } catch (err) {
      console.error('[CompanyService] fetchMerged error', err);
      return null;
    }
  }

  updateCompany(restaurantId: string, payload: Partial<Company>): Observable<Company | null> {
    return from(this.updateMerged(restaurantId, payload));
  }

  private async updateMerged(restaurantId: string, payload: any): Promise<Company | null> {
    try {
      // Campi che vanno su Platea restaurants
      const plateaFields = ['name', 'address', 'city', 'province', 'email', 'phone'];
      const plateaPayload: any = {};
      plateaFields.forEach(f => {
        if (payload[f] !== undefined) plateaPayload[f] = payload[f];
      });

      // Campi che vanno su Timbrature companies
      const timbratureFields = [
        'opening_hours', 'timbratura_type', 'punch_points',
        'closed_days', 'manager_visibility', 'vat', 'website',
        'numero_telefono', 'address', 'city', 'province'
      ];
      const timbraturePayload: any = {};
      timbratureFields.forEach(f => {
        if (payload[f] !== undefined) timbraturePayload[f] = payload[f];
      });

      // 1. Aggiorna Platea se necessario
      if (Object.keys(plateaPayload).length > 0) {
        await this.plateaSupabase
          .from('restaurants')
          .update({ ...plateaPayload, updated_at: new Date().toISOString() })
          .eq('id', restaurantId);
      }

      // 2. Trova/crea il record companies in Timbrature
      if (Object.keys(timbraturePayload).length > 0) {
        // Prima trova owner_id del ristorante
        const { data: restaurant } = await this.plateaSupabase
          .from('restaurants')
          .select('owner_id, name')
          .eq('id', restaurantId)
          .maybeSingle();

        if (restaurant) {
          const { data: existing } = await this.timbratureSupabase
            .from('companies')
            .select('id')
            .eq('admin_user_id', restaurant.owner_id)
            .maybeSingle();

          if (existing) {
            // Aggiorna
            await this.timbratureSupabase
              .from('companies')
              .update({ ...timbraturePayload, updated_at: new Date().toISOString() })
              .eq('id', existing.id);
          } else {
            // Crea nuovo record
            await this.timbratureSupabase
              .from('companies')
              .insert({
                admin_user_id: restaurant.owner_id,
                name: restaurant.name,
                ...timbraturePayload,
                created_at: new Date().toISOString(),
                updated_at: new Date().toISOString()
              });
          }
        }
      }

      // 3. Ritorna il dato aggiornato
      return this.fetchMerged(restaurantId);
    } catch (err) {
      console.error('[CompanyService] updateMerged error', err);
      return null;
    }
  }

  getAllCompanies(): Observable<Company[]> {
    return from(
      this.plateaSupabase
        .from('restaurants')
        .select('*')
        .then((res: any) => (res.data || []).map((r: any) => ({
          id: r.id,
          name: r.name,
          admin_user_id: r.owner_id,
        }) as Company))
    );
  }

  // ── Metodi visibilità ──

  resolveManagerConfig(company: Company | null, managerId: string | null): ManagerVisibilityConfig {
    if (!company || !managerId) return this.getDefaultManagerConfig();
    const visibility = (company as any).manager_visibility || {};
    const config = visibility[managerId] || {};
    return {
      mode: config.mode ?? 'self',
      user_ids: Array.isArray(config.user_ids) ? config.user_ids : [],
      roles: Array.isArray(config.roles) ? config.roles : [],
      department_ids: Array.isArray(config.department_ids) ? config.department_ids : [],
      can_view_all_employees: !!config.can_view_all_employees,
      can_manage_departments: !!config.can_manage_departments,
      can_manage_job_titles: !!config.can_manage_job_titles,
      can_view_reports: !!config.can_view_reports,
      can_edit_employees: !!config.can_edit_employees,
      can_modify_timbrature: !!config.can_modify_timbrature,
    };
  }

  filterEmployeesByVisibility(employees: User[], company: Company | null, managerId: string | null): User[] {
    if (!Array.isArray(employees) || employees.length === 0) return [];
    const config = this.resolveManagerConfig(company, managerId);
    if (config.can_view_all_employees) return employees;
    switch (config.mode) {
      case 'self':
        return employees.filter(e => e.id === managerId);
      case 'selected_users':
        return employees.filter(e => config.user_ids?.includes(e.id));
      case 'roles':
        return employees.filter(e => e.role && config.roles?.includes(e.role as string));
      case 'department':
        return employees.filter(e => {
          const deptId = (e as any).department_id || (e as any).department?.id;
          return deptId && config.department_ids?.includes(deptId);
        });
      default:
        return employees.filter(e => e.id === managerId);
    }
  }

  private getDefaultManagerConfig(): ManagerVisibilityConfig {
    return {
      mode: 'self', user_ids: [], roles: [], department_ids: [],
      can_view_all_employees: false, can_manage_departments: false,
      can_manage_job_titles: false, can_view_reports: false,
      can_edit_employees: false, can_modify_timbrature: false,
    };
  }
}